+
+        if let ReplayEvent::RegionClosed { region, outcome } = event {
+            assert_eq!(region.0, 5);
+            assert_eq!(outcome, Severity::Ok.as_u8());
+        } else {
+            panic!("Expected RegionClosed");
+        }
